# Wyciąg z intencje.py
def wykryj_intencje(pytanie: str) -> str:
    p = pytanie.lower()
    # Usunięcie polskich znaków diakrytycznych
    p = usun_ogonki(p)

    intencje = pobierz_konfiguracje_intencji()
    for typ, wzorce in intencje:
        if any(w in p for w in wzorce):
            return typ
    return "OGOLNE"
